const divContainer=document.querySelector("div.card-container"),buttonCheckout=document.querySelector("div.shoping-cart"),inputBuscar=document.querySelector("input#inputSearch"),productos=[],categorias=[],carrito=recuperarCarrito(),URLProds=obtenerEndpoint()||"";function mostrarToast(r,t){Swal.fire({toast:!0,position:"top-end",showConfirmButton:!1,timer:2800,timerProgressBar:!0,theme:"dark",icon:r,text:t.trim()})}function guardarCarrito(){localStorage.setItem("carritoTeclab",JSON.stringify(carrito))}function recuperarCarrito(){return JSON.parse(localStorage.getItem("carritoTeclab"))||[]}function obtenerEndpoint(){return localStorage.getItem("URLproductos")||""}function mostrarAnio(){document.querySelector("span#year").textContent=(new Date).getFullYear()}function activarClickComprar(){const r=document.querySelectorAll("button#buttonComprar");r.length>0&&r.forEach((r=>{r.addEventListener("click",(()=>{const t=r.dataset.codigo,o=productos.find((r=>r.codigo===t));carrito.push(o),mostrarToast("success",`${o.nombre} agregado al carrito.`),guardarCarrito()}))}))}function crearCardHTML({codigo:r,nombre:t,precio:o,imagen:a}){return`<div class="card">\n                <div class="product-image" data-image="${r}">${a}</div>\n                <div class="product-name">${t}</div>\n                <div class="product-price">$ ${o.toLocaleString()}</div>\n                <div class="buy-button">\n                    <button id="buttonComprar" class="button-comprar" data-codigo="${r}" >COMPRAR</button>\n                </div>\n            </div>`}function crearCardErrorHTML(){return'<div class="card-error">\n                <div class="error-title">\n                    <h3>Se ha producido un error inesperado.</h3>\n                    <div class="emoji-error">🔌</div>\n                    <h4>Por favor, intenta acceder nuevamente en unos instantes.</h4>\n                    <p>No estamos pudiendo cargar el listado de productos para tu compra.</p>\n                    <div class="emoji-error">\n                        <span>👩🏻‍💻</span>\n                        <span>💻</span>\n                        <span>🔈</span>\n                        <span>⌚️</span>\n                    </div>\n                </div>\n            </div>'}function cargarProductos(r){if(r.length>0){let t="";r.forEach((r=>{t+=crearCardHTML(r),divContainer.innerHTML=t})),activarClickComprar()}else divContainer.innerHTML=crearCardErrorHTML()}function armarCategoriaSpan(r){return`<span id="categoriaId" class="category">${r}</span>`}function cargarCategorias(){if(categorias.push(...new Set(productos.map((r=>r.categoria)))),categorias.length>0){let r="";categorias.forEach((t=>r+=armarCategoriaSpan(t))),document.querySelector("article#categoriasContainer").innerHTML+=r,activarClickEnCategorias()}}function activarClickEnCategorias(){const r=document.querySelectorAll("span#categoriaId");r.length>0&&r.forEach((r=>{r.addEventListener("click",(()=>{if("Todos"!==r.textContent){let t=r.textContent;const o=productos.filter((r=>r.categoria===t));o.length>0&&cargarProductos(o)}else cargarProductos(productos)}))}))}function obtenerProductos(){URLProds?fetch(URLProds).then((r=>{if(r.ok)return r.json();throw new Error("Error al obtener los productos.")})).then((r=>productos.push(...r))).then((()=>cargarProductos(productos))).then((()=>cargarCategorias())).catch((r=>divContainer.innerHTML=crearCardErrorHTML())):divContainer.innerHTML=crearCardErrorHTML()}function filtrarProductos(){if(""!==inputBuscar.value.trim()){let r=inputBuscar.value.toLowerCase().trim();const t=productos.filter((t=>t.nombre.toLowerCase().includes(r)));t.length>0?cargarProductos(t):mostrarToast("warning","No se encontraron productos.")}}obtenerProductos(),mostrarAnio(),buttonCheckout.addEventListener("mousemove",(()=>{buttonCheckout.title=0===carrito.length?"Carrito vacío":`${carrito.length} producto(s).`})),buttonCheckout.addEventListener("click",(()=>{0!==carrito.length?location.href="checkout.html":mostrarToast("warning","Carga productos en el carrito.")})),inputBuscar.addEventListener("search",filtrarProductos),inputBuscar.addEventListener("keydown",(r=>"Enter"===r.key&&filtrarProductos()));